external_knowledge:
- 'Most accurate model' refers to the model with the highest training accuracy; 
- 'Authorized users' refers to users who have been granted the appropriate permissions (can_view, can_train, can_predict); 
- 'Most authorized users first' refers to the model with the highest number of users who can view, train, or predict the model.

sql:
SELECT model_id 
FROM model_trainings 
WHERE training_date = '2023-01-15' AND training_accuracy = 0.95;

SELECT DISTINCT M.model_name
FROM models M
WHERE M.model_id IN (
  SELECT MI.model_id
  FROM model_inputs MI
);
